import itertools

class Solution:
    def maxPower(self, stations, r, k):
        n = len(stations)
        best = -1
        for combo in itertools.combinations_with_replacement(range(n), k):
            added = [0] * n
            for c in combo:
                added[c] += 1
            combined = [stations[i] + added[i] for i in range(n)]
            prefix = [0] * (n + 1)
            for i in range(n):
                prefix[i + 1] = prefix[i] + combined[i]
            weakest = min(
                prefix[min(n - 1, i + r) + 1] - prefix[max(0, i - r)]
                for i in range(n)
            )
            if weakest > best:
                best = weakest
        return best

