class Solution:
    def maxPower(self, stations, r, k):
        n = len(stations)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + stations[i]

        def window_sum(i):
            lo = max(0, i - r)
            hi = min(n - 1, i + r)
            return prefix[hi + 1] - prefix[lo]

        base = [window_sum(i) for i in range(n)]

        def feasible(target):
            diff = [0] * (n + 1)
            used = 0
            running_extra = 0
            for i in range(n):
                running_extra += diff[i]
                power = base[i] + running_extra
                if power < target:
                    need = target - power
                    used += need
                    if used > k:
                        return False
                    running_extra += need
                    place = min(n - 1, i + r)
                    reach_end = min(n, place + r + 1)
                    diff[reach_end] -= need
            return used <= k

        lo, hi = min(base), sum(stations) + k
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

