var maxPower = function(stations, r, k) {
    const n = stations.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + stations[i];
    }
    const windowSum = (i) => {
        const lo = Math.max(0, i - r);
        const hi = Math.min(n - 1, i + r);
        return prefix[hi + 1] - prefix[lo];
    };
    const base = new Array(n);
    for (let i = 0; i < n; i++) base[i] = windowSum(i);

    const feasible = (target) => {
        const diff = new Array(n + 1).fill(0);
        let used = 0;
        let runningExtra = 0;
        for (let i = 0; i < n; i++) {
            runningExtra += diff[i];
            const power = base[i] + runningExtra;
            if (power < target) {
                const need = target - power;
                used += need;
                if (used > k) return false;
                runningExtra += need;
                const place = Math.min(n - 1, i + r);
                const reachEnd = Math.min(n, place + r + 1);
                diff[reachEnd] -= need;
            }
        }
        return used <= k;
    };

    let lo = base[0];
    for (let i = 1; i < n; i++) {
        if (base[i] < lo) lo = base[i];
    }
    let hi = stations.reduce((a, b) => a + b, 0) + k;
    while (lo < hi) {
        const mid = Math.floor((lo + hi + 1) / 2);
        if (feasible(mid)) {
            lo = mid;
        } else {
            hi = mid - 1;
        }
    }
    return lo;
};
